            return IOUtils.toByteArray(inputStream);

        } catch (MalformedURLException e) {
            throw new IllegalArgumentException("Invalid URL format: " + resourceUrl, e);
        } catch (IOException e) {
            throw new IllegalArgumentException("Failed to fetch resource from URL: " + resourceUrl, e);
        } finally {
            // Clean up resources
            if (inputStream != null) {
                try {
                    inputStream.close();
                } catch (IOException e) {
                    // Log this in production
                }
            }
            if (connection != null) {
                connection.disconnect();
            }
        }
    }
}
